 1	/**
 2	 * A generic dropdown menu component for actions, utilizing PatternFly components. It allows for actions to be specified
 3	 * per item, with each action having a label and an onClick handler. This component is flexible for use with various
 4	 * item types and action configurations.
 5	 *
 6	 * @module actionMenu
 7	 */
 8	import React, { useState } from 'react';
 9	import {
10	  Dropdown,
11	  DropdownItem,
12	  DropdownList,
13	  MenuToggle,
14	  type MenuToggleElement,
15	  type PopperProps,
16	  type TooltipProps
17	} from '@patternfly/react-core';
18	import { EllipsisVIcon } from '@patternfly/react-icons';
19	
20	type Action<T> = {
21	  label: string;
22	  onClick: (item: T) => void;
23	  disabled?: boolean;
24	  ouiaId?: string; // Optional ouiaId for E2E testing
25	  tooltipProps?: TooltipProps;
26	};
27	
28	interface ActionMenuProps<T = unknown> {
29	  item: T;
30	  actions: Action<T>[];
31	  popperProps?: Partial<PopperProps>;
32	}
33	
34	const ActionMenu = <T,>({ item, actions, popperProps }: ActionMenuProps<T>) => {
35	  const [isOpen, setIsOpen] = useState<boolean>(false);
36	
37	  return (
38	    <Dropdown
39	      isOpen={isOpen}
40	      popperProps={popperProps}
41	      onOpenChange={setIsOpen}
42	      onSelect={() => setIsOpen(false)}
43	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
44	        <MenuToggle
45	          ref={toggleRef}
46	          aria-label="Action Menu Toggle"
47	          variant="plain"
48	          onClick={() => setIsOpen(prev => !prev)}
49	          isExpanded={isOpen}
50	          data-ouia-component-id="action_menu_toggle"
51	        >
52	          <EllipsisVIcon />
53	        </MenuToggle>
54	      )}
55	      shouldFocusToggleOnSelect
56	    >
57	      <DropdownList>
58	        {actions.map(a => (
59	          <DropdownItem
60	            value={a.label}
61	            key={a.label}
62	            ouiaId={a.ouiaId}
63	            onClick={() => {
64	              a.onClick(item);
65	            }}
66	            isAriaDisabled={a.disabled}
67	            tooltipProps={a.tooltipProps}
68	          >
69	            {a.label}
70	          </DropdownItem>
71	        ))}
72	      </DropdownList>
73	    </Dropdown>
74	  );
75	};
76	
77	export { ActionMenu as default, ActionMenu, type ActionMenuProps };

